    /// The composer footer shows the current model, which lives on the
    /// per-session runtime status — and that status is only ever created by a
    /// `session/status/read`. So opening a session must queue one (when the
    /// server advertises it), otherwise the model never appears until the user
    /// happens to open a status/model menu.
    #[test]
    fn session_open_enqueues_session_status_read_when_supported() {
        use octos_core::SessionKey;
        use octos_core::ui_protocol::SessionOpened;

        let mut store =
            protocol_store_with_methods(&[crate::model::APPUI_METHOD_SESSION_STATUS_READ]);
        let session_id = SessionKey("dev:local:soak#main".into());
        let opened: SessionOpened = serde_json::from_value(serde_json::json!({
            "session_id": session_id.clone(),
            "active_profile_id": "dev",
        }))
        .expect("session/opened payload");
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionOpened(opened)));

        let mut saw_status_read = false;
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                if params.session_id == session_id {
                    saw_status_read = true;
                }
            }
        }
        assert!(
            saw_status_read,
            "session open should enqueue session/status/read so the composer footer can show the current model"
        );
    }

    /// A server that does not advertise `session/status/read` must not be
    /// probed on session open — old backends stay untouched.
    #[test]
    fn session_open_skips_status_read_when_capability_absent() {
        use octos_core::SessionKey;
        use octos_core::ui_protocol::SessionOpened;

        let mut store =
            protocol_store_with_methods(&[crate::model::APPUI_METHOD_PROFILE_LOCAL_CREATE]);
        let opened: SessionOpened = serde_json::from_value(serde_json::json!({
            "session_id": SessionKey("dev:local:soak#main".into()),
            "active_profile_id": "dev",
        }))
        .expect("session/opened payload");
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionOpened(opened)));

        let mut commands = Vec::new();
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            commands.push(command);
        }
        assert!(
            !commands
                .iter()
                .any(|command| matches!(command, AppUiCommand::ReadSessionStatus(_))),
            "no session/status/read should be queued when the capability is unadvertised; got {commands:?}"
        );
    }

    /// `session/opened` can land BEFORE the capabilities response, in which
    /// case the open-time probe is skipped (the gate is still unknown). Once
    /// capabilities arrive, already-open sessions without a runtime status must
    /// be probed — otherwise the composer footer's model stays blank forever.
    #[test]
    fn capabilities_arriving_after_session_open_requeue_status_read() {
        let mut store = store_with_empty_session();
        let session_id = store.state.sessions[0].id.clone();
        assert!(
            store.state.capabilities.is_none(),
            "test premise: open-before-caps"
        );

        store.apply_client_event(ClientEvent::Capabilities(CapabilitiesClientEvent {
            result: crate::model::ConfigCapabilitiesListResult {
                capabilities: UiProtocolCapabilities::new(
                    &[crate::model::APPUI_METHOD_SESSION_STATUS_READ],
                    &[],
                ),
            },
            message: "Octos UI capabilities refreshed".into(),
        }));

        let mut saw_status_read = false;
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                if params.session_id == session_id {
                    saw_status_read = true;
                }
            }
        }
        assert!(
            saw_status_read,
            "capabilities arriving after session open must requeue session/status/read"
        );
    }

    /// The late-capabilities probe covers ONLY the active session — one queue
    /// entry. Bulk-probing every open session could overflow the 16-entry
    /// autonomy-hydration queue and evict unrelated pending commands; inactive
    /// sessions probe lazily when they become active.
    #[test]
    fn capabilities_probe_targets_only_the_active_session() {
        let mut store = store_with_two_sessions("local:a", "local:b");
        store.apply_client_event(ClientEvent::Capabilities(CapabilitiesClientEvent {
            result: crate::model::ConfigCapabilitiesListResult {
                capabilities: UiProtocolCapabilities::new(
                    &[crate::model::APPUI_METHOD_SESSION_STATUS_READ],
                    &[],
                ),
            },
            message: "Octos UI capabilities refreshed".into(),
        }));

        let mut status_reads = Vec::new();
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                status_reads.push(params.session_id);
            }
        }
        assert_eq!(
            status_reads,
            vec![SessionKey("local:a".into())],
            "exactly one probe, for the active session"
        );
    }

    /// Sessions-pane navigation (every path funnels through the shared
    /// `switch_selected_session` bundle) probes the incoming session's status
    /// when it is missing — a session that raced the capabilities response gets
    /// its footer model on first visit, not only via the /resume flow.
    #[test]
    fn direct_session_switch_probes_missing_status() {
        let mut store = store_with_two_sessions("local:a", "local:b");
        store.state.capabilities = Some(crate::menu::CapabilitySet::from_methods([
            crate::model::APPUI_METHOD_SESSION_STATUS_READ,
        ]));

        store.state.switch_selected_session(1);

        let mut status_reads = Vec::new();
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                status_reads.push(params.session_id);
            }
        }
        assert_eq!(
            status_reads,
            vec![SessionKey("local:b".into())],
            "switching to an unprobed session queues exactly its status read"
        );

        // Without the capability the switch probes nothing.
        let mut ungated = store_with_two_sessions("local:a", "local:b");
        ungated.state.switch_selected_session(1);
        assert!(
            ungated.state.dequeue_autonomy_hydration().is_none(),
            "no capability advertised → no probe on switch"
        );
    }

    /// A fresh `session/opened` both switches to the session (bundle probe)
    /// and probes explicitly; rapid switches re-probe before a response lands.
    /// Duplicates eat slots of the 16-capped hydration queue and can evict
    /// unrelated pending commands — probes must dedupe against the queue.
    #[test]
    fn status_probes_deduplicate_against_the_pending_queue() {
        use octos_core::ui_protocol::SessionOpened;

        // Session open: the switch-bundle probe and the open-time probe must
        // collapse to ONE queued read.
        let mut store =
            protocol_store_with_methods(&[crate::model::APPUI_METHOD_SESSION_STATUS_READ]);
        let session_id = SessionKey("dev:local:opened#main".into());
        let opened: SessionOpened = serde_json::from_value(serde_json::json!({
            "session_id": session_id.clone(),
            "active_profile_id": "dev",
        }))
        .expect("session/opened payload");
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionOpened(opened)));

        let mut reads = Vec::new();
        while let Some(command) = store.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                reads.push(params.session_id);
            }
        }
        assert_eq!(
            reads,
            vec![session_id],
            "open + switch must queue exactly one status read"
        );

        // Switch burst: bouncing between two unprobed sessions queues one read
        // per session, not one per switch.
        let mut burst = store_with_two_sessions("local:a", "local:b");
        burst.state.capabilities = Some(crate::menu::CapabilitySet::from_methods([
            crate::model::APPUI_METHOD_SESSION_STATUS_READ,
        ]));
        for index in [1, 0, 1, 0, 1] {
            burst.state.switch_selected_session(index);
        }
        let mut burst_reads = Vec::new();
        while let Some(command) = burst.state.dequeue_autonomy_hydration() {
            if let AppUiCommand::ReadSessionStatus(params) = command {
                burst_reads.push(params.session_id);
            }
        }
        assert_eq!(
            burst_reads,
            vec![SessionKey("local:b".into()), SessionKey("local:a".into())],
            "a switch burst queues one probe per session, not per switch"
        );
    }

    /// A snapshot replay landing mid-turn must not un-time the live turn — the
    /// per-turn clock is local-only state, carried over like `live_reasoning`.
    #[test]
    fn per_turn_clock_survives_snapshot_replay() {
        let mut store = store_with_two_sessions("local:a", "local:b");
        let a = SessionKey("local:a".into());
        let turn_id = TurnId::new();
        store.state.note_turn_started(&a, &turn_id);

        store.apply_event(AppUiEvent::Snapshot(AppUiSnapshot {
            sessions: vec![SessionView {
                id: a.clone(),
                title: "local:a".into(),
                profile_id: Some("coding".into()),
                messages: vec![],
                tasks: vec![],
                live_reply: None,
            }],
            selected_session: 0,
            status: "replayed".into(),
            target: None,
            readonly: false,
        }));

        assert!(
            store
                .state
                .turn_started_at
                .contains_key(&(a.clone(), turn_id.clone())),
            "the per-turn clock must survive a snapshot replay"
        );
        assert!(
            store.state.take_turn_elapsed_secs(&a, &turn_id).is_some(),
            "the surviving clock still yields an elapsed duration"
        );
    }

    /// The committed status report must time the TURN, not the current visit to
    /// it: a turn on a non-selected session (the global run-state clock never
    /// timed it) still records a report from its own `TurnStarted` clock.
    #[test]
    fn turn_summary_times_background_session_turn() {
        let mut store = store_with_empty_session();
        let background = SessionView {
            id: SessionKey("local:background".into()),
            title: "background".into(),
            profile_id: Some("coding".into()),
            messages: vec![],
            tasks: vec![],
            live_reply: None,
        };
        store.state.sessions.push(background);
        let background_id = store.state.sessions[1].id.clone();
        let turn_id = TurnId::new();

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnStarted(
            TurnStartedEvent {
                session_id: background_id.clone(),
                turn_id: turn_id.clone(),
                timestamp: chrono::Utc::now(),
                topic: None,
            },
        )));
        // Selection stays on the foreground session; the background turn's
        // completion must still record a report (previously: none at all).
        assert_eq!(store.state.selected_session, 0);
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: background_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));

        let summary = store
            .state
            .turn_summary_for(&turn_id)
            .expect("background-session turn completion records a status report");
        assert_eq!(summary.session_id, background_id);
        assert!(
            store.state.turn_started_at.is_empty(),
            "the per-turn clock entry drains at the terminal event"
        );
    }

    #[test]
    fn tool_started_records_live_reply_segment_boundary_at_segment_offset() {
        // The REAL per-segment boundary signal. A tool call starting means the
        // current assistant CONTENT segment just ended, so the live-reply length
        // at that moment is exactly where the live-delta renderer must start the
        // next segment as a fresh markdown block. Without this, an agentic turn's
        // later "### Step N" glued onto the previous segment's body on the real
        // terminal event fires at turn end with the full length — the wrong
        // offset — so it never split mid-turn).
        let turn_id = TurnId::new();
        let text = "### Step 1\n\nBody one.";
        let mut store = store_with_live_reply(turn_id.clone(), text);
        let session_id = store.state.sessions[0].id.clone();

        store.apply_event(AppUiEvent::Protocol(UiNotification::ToolStarted(
            ToolStartedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                tool_call_id: "call-1".into(),
                tool_name: "write_file".into(),
                arguments: None,
            },
        )));

        assert_eq!(
            store
                .state
                .live_reply_segment_boundaries
                .get(&(session_id, turn_id))
                .cloned(),
            Some(vec![text.len()]),
            "a tool call starting mid-turn must record the current live-reply length as a segment boundary"
        );
    }

    #[test]
    fn server_initiated_continuation_turn_with_turn_started_renders_its_answer() {
        // Live-rendering bug (mini5): a single user prompt expanded into
        // server-INITIATED master-continuation turns (reason=child_completed /
        // scatter_join_complete). When the continuation turn's TurnStarted IS
        // delivered, its deltas must accumulate and commit as a real assistant
        // message — never the "did not receive a final assistant answer"
        // fallback card.
        let original_turn = TurnId::new();
        let continuation = TurnId::new();
        let mut store = store_with_live_reply(original_turn.clone(), "original answer");
        let session_id = store.state.sessions[0].id.clone();

        // Original user turn completes first and clears live_reply.
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: original_turn,
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));

        // Server-initiated continuation turn: TurnStarted delivered, then deltas.
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnStarted(
            TurnStartedEvent {
                session_id: session_id.clone(),
                turn_id: continuation.clone(),
                timestamp: chrono::Utc::now(),
                topic: None,
            },
        )));
        for chunk in ["the ", "answer"] {
            store.apply_event(AppUiEvent::Protocol(UiNotification::MessageDelta(
                MessageDeltaEvent {
                    session_id: session_id.clone(),
                    topic: None,
                    turn_id: continuation.clone(),
                    text: chunk.into(),
                },
            )));
        }
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id,
                topic: None,
                turn_id: continuation,
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));

        let contents: Vec<&str> = store.state.sessions[0]
            .messages
            .iter()
            .map(|m| m.content.as_str())
            .collect();
        assert!(
            contents.iter().any(|c| c.contains("the answer")),
            "continuation answer must render: {contents:?}"
        );
        assert!(
            !contents
                .iter()
                .any(|c| c.contains("did not receive a final assistant answer")),
            "continuation turn with deltas must NOT show the fallback card: {contents:?}"
        );
    }

    #[test]
    fn reasoning_delta_populates_committed_message_reasoning_content() {
        use octos_core::ui_protocol::{
            MessageDeltaEvent, ReasoningDeltaEvent, TurnCompletedEvent, TurnStartedEvent,
        };
        let mut store = protocol_store_with_autonomy();
        let session_id = store.state.sessions[0].id.clone();
        let turn_id = TurnId::new();
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnStarted(
            TurnStartedEvent {
                session_id: session_id.clone(),
                turn_id: turn_id.clone(),
                timestamp: chrono::Utc::now(),
                topic: None,
            },
        )));
        // Streamed reasoning arrives interleaved with the answer text.
        store.apply_event(AppUiEvent::Protocol(UiNotification::ReasoningDelta(
            ReasoningDeltaEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                text: "weighing the options".into(),
            },
        )));
        store.apply_event(AppUiEvent::Protocol(UiNotification::MessageDelta(
            MessageDeltaEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                text: "the answer".into(),
            },
        )));
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));
        // The committed message carries the streamed reasoning as reasoning_content,
        // which the transcript renders as a "· reasoning" block.
        let reasoning = store.state.sessions[0]
            .messages
            .iter()
            .find_map(|message| message.reasoning_content.as_deref());
        assert_eq!(
            reasoning,
            Some("weighing the options"),
            "ReasoningDelta must populate the committed message's reasoning_content"
        );
    }

    #[test]
    fn reasoning_without_answer_attaches_to_fallback_message() {
        use octos_core::ui_protocol::{ReasoningDeltaEvent, TurnCompletedEvent};
        let mut store = protocol_store_with_autonomy();
        let session_id = store.state.sessions[0].id.clone();
        let turn_id = TurnId::new();
        // Reasoning streams but no answer text arrives — the terminal hits the
        // None arm of commit_live_reply (codex review: reasoning must not be lost).
        store.apply_event(AppUiEvent::Protocol(UiNotification::ReasoningDelta(
            ReasoningDeltaEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                text: "no answer came".into(),
            },
        )));
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));
        let reasoning = store.state.sessions[0]
            .messages
            .iter()
            .find_map(|message| message.reasoning_content.as_deref());
        assert_eq!(
            reasoning,
            Some("no answer came"),
            "reasoning must attach to the fallback message even with no answer"
        );
    }

    /// Local-only turn-lifecycle guards must survive a snapshot replay
    /// (reconnect/refresh), like `composer_history` does. Losing
    /// `completed_turns` reopens the #218 late-delta wedge after reconnect:
    /// `is_turn_completed` returns false for a turn that terminated before the
    /// replay, so a late delta resurrects the dead turn into `live_reply`.
    #[test]
    fn turn_lifecycle_guards_survive_snapshot_replay() {
        let mut store = store_with_empty_session();
        let session_id = store.state.sessions[0].id.clone();
        let turn_id = TurnId::new();
        let switched_turn = TurnId::new();
        store.state.mark_turn_completed(&session_id, &turn_id);
        store
            .state
            .mark_turn_finalized_by_switch(&session_id, &switched_turn);
        store.state.live_reasoning.insert(
            (session_id.clone(), turn_id.clone()),
            "carried thinking".into(),
        );
        store
            .state
            .session_usage
            .insert(session_id.clone(), (Some(10), Some(20), Some(0.5)));
        store
            .state
            .session_context_window
            .insert(session_id.clone(), 200_000);

        store.apply_event(AppUiEvent::Snapshot(AppUiSnapshot {
            sessions: vec![SessionView {
                id: session_id.clone(),
                title: "test".into(),
                profile_id: Some("coding".into()),
                messages: vec![],
                tasks: vec![],
                live_reply: None,
            }],
            selected_session: 0,
            status: "replayed".into(),
            target: None,
            readonly: false,
        }));

        assert!(
            store.state.is_turn_completed(&session_id, &turn_id),
            "completed_turns must survive a snapshot replay"
        );
        assert!(
            store
                .state
                .take_turn_finalized_by_switch(&session_id, &switched_turn),
            "finalized_by_switch must survive a snapshot replay"
        );
        assert_eq!(
            store
                .state
                .live_reasoning
                .get(&(session_id.clone(), turn_id.clone()))
                .map(String::as_str),
            Some("carried thinking"),
            "live_reasoning must survive a snapshot replay"
        );
        assert_eq!(
            store.state.session_usage.get(&session_id),
            Some(&(Some(10), Some(20), Some(0.5))),
            "session_usage must survive a snapshot replay"
        );
        assert_eq!(
            store.state.session_context_window.get(&session_id),
            Some(&200_000),
            "session_context_window must survive a snapshot replay"
        );
    }

    /// `fail_live_reply` must drain the turn's streamed reasoning like
    /// `commit_live_reply` does: attach it to the failure card (partial-answer
    /// arm) and remove the accumulator entry — otherwise the entry leaks and
    /// the reasoning is missing from the card.
    #[test]
    fn turn_error_drains_live_reasoning_onto_failure_card() {
        let turn_id = TurnId::new();
        let mut store = store_with_live_reply(turn_id.clone(), "partial answer");
        let session_id = store.state.sessions[0].id.clone();
        store.state.live_reasoning.insert(
            (session_id.clone(), turn_id.clone()),
            "weighing the options".into(),
        );

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnError(
            TurnErrorEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                code: "internal".into(),
                message: "boom".into(),
            },
        )));

        let card = store.state.sessions[0]
            .messages
            .last()
            .expect("failure card pushed");
        assert_eq!(
            card.reasoning_content.as_deref(),
            Some("weighing the options"),
            "the failure card must carry the streamed reasoning"
        );
        assert!(
            !store
                .state
                .live_reasoning
                .contains_key(&(session_id, turn_id)),
            "the accumulator entry must be drained on the error terminal"
        );
    }

    /// The no-live-reply error arm (fallback card) must also surface the
    /// streamed reasoning, mirroring `commit_live_reply`'s None arm.
    #[test]
    fn turn_error_without_live_reply_attaches_reasoning_to_fallback_card() {
        let turn_id = TurnId::new();
        let mut store = store_with_empty_session();
        let session_id = store.state.sessions[0].id.clone();
        store.state.live_reasoning.insert(
            (session_id.clone(), turn_id.clone()),
            "no answer came".into(),
        );

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnError(
            TurnErrorEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                code: "internal".into(),
                message: "boom".into(),
            },
        )));

        let card = store.state.sessions[0]
            .messages
            .last()
            .expect("failure card pushed");
        assert_eq!(card.reasoning_content.as_deref(), Some("no answer came"));
        assert!(
            !store
                .state
                .live_reasoning
                .contains_key(&(session_id, turn_id)),
            "the accumulator entry must be drained on the fallback error arm"
        );
    }

    /// A STALE turn error (a different turn's reply is live, no
    /// finalized-by-switch marker) commits nothing — the errored turn's
    /// reasoning must be preserved for its real terminal, mirroring
    /// `commit_live_reply`'s stale arm.
    #[test]
    fn stale_turn_error_preserves_other_turns_reasoning() {
        let live_turn = TurnId::new();
        let errored_turn = TurnId::new();
        let mut store = store_with_live_reply(live_turn.clone(), "still streaming");
        let session_id = store.state.sessions[0].id.clone();
        store
            .state
            .live_reasoning
            .insert((session_id.clone(), errored_turn.clone()), "keep me".into());

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnError(
            TurnErrorEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: errored_turn.clone(),
                code: "internal".into(),
                message: "boom".into(),
            },
        )));

        assert_eq!(
            store
                .state
                .live_reasoning
                .get(&(session_id, errored_turn))
                .map(String::as_str),
            Some("keep me"),
            "a stale error must not drop the errored turn's reasoning"
        );
    }

    /// Duplicate terminal idempotence: a second `turn/completed` for a turn
    /// that already terminated (e.g. replayed after reconnect) must be a
    /// no-op — exactly one committed card, no false "no final answer"
    /// fallback, no run-state flip.
    #[test]
    fn duplicate_turn_completed_is_a_noop() {
        let turn_id = TurnId::new();
        let mut store = store_with_live_reply(turn_id.clone(), "the answer");
        let session_id = store.state.sessions[0].id.clone();
        let completed = TurnCompletedEvent {
            session_id: session_id.clone(),
            topic: None,
            turn_id: turn_id.clone(),
            cursor: None,
            tokens_in: None,
            tokens_out: None,
            session_result: None,
        };

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            completed.clone(),
        )));
        assert_eq!(store.state.sessions[0].messages.len(), 1);
        assert_eq!(store.state.sessions[0].messages[0].content, "the answer");
        let status_after_first = store.state.status.clone();

        // Replayed duplicate: live_reply is now None, so without the guard the
        // None arm would push a FALSE "completed with no final answer" card.
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            completed,
        )));
        assert_eq!(
            store.state.sessions[0].messages.len(),
            1,
            "the duplicate terminal must not push a second card"
        );
        assert_eq!(
            store.state.status, status_after_first,
            "the duplicate terminal must not rewrite the status line"
        );
    }

    /// A late/replayed `turn/error` for a turn that already completed must
    /// not push a failure card or flip the run state to Error.
    #[test]
    fn turn_error_after_completed_terminal_is_a_noop() {
        let turn_id = TurnId::new();
        let mut store = store_with_live_reply(turn_id.clone(), "the answer");
        let session_id = store.state.sessions[0].id.clone();

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: turn_id.clone(),
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));
        assert_eq!(store.state.sessions[0].messages.len(), 1);
        assert_eq!(store.state.run_state.label(), "done");

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnError(
            TurnErrorEvent {
                session_id,
                topic: None,
                turn_id,
                code: "internal".into(),
                message: "late replayed error".into(),
            },
        )));
        assert_eq!(
            store.state.sessions[0].messages.len(),
            1,
            "a replayed error for an already-terminal turn must not push a failure card"
        );
        assert_ne!(
            store.state.run_state.label(),
            "error",
            "a replayed error must not flip the run state"
        );
    }

    #[test]
    fn continuation_turn_without_turn_started_lazy_binds_and_renders_answer() {
        // Decisive sub-case: the continuation turn's TurnStarted is NOT delivered
        // to this connection, so deltas arrive against `live_reply == None`. They
        // must LAZY-BIND a fresh live_reply for the turn and accumulate, so the
        // turn commits its real answer instead of the fallback card.
        let original_turn = TurnId::new();
        let continuation = TurnId::new();
        let mut store = store_with_live_reply(original_turn.clone(), "original answer");
        let session_id = store.state.sessions[0].id.clone();

        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id: session_id.clone(),
                topic: None,
                turn_id: original_turn,
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));
        assert!(store.state.sessions[0].live_reply.is_none());

        // No TurnStarted for the continuation: deltas arrive first.
        for chunk in ["the ", "answer"] {
            store.apply_event(AppUiEvent::Protocol(UiNotification::MessageDelta(
                MessageDeltaEvent {
                    session_id: session_id.clone(),
                    topic: None,
                    turn_id: continuation.clone(),
                    text: chunk.into(),
                },
            )));
        }
        store.apply_event(AppUiEvent::Protocol(UiNotification::TurnCompleted(
            TurnCompletedEvent {
                session_id,
                topic: None,
                turn_id: continuation,
                cursor: None,
                tokens_in: None,
                tokens_out: None,
                session_result: None,
            },
        )));

        let contents: Vec<&str> = store.state.sessions[0]
            .messages
            .iter()
            .map(|m| m.content.as_str())
            .collect();
        assert!(
            contents.iter().any(|c| c.contains("the answer")),
            "lazy-bound continuation answer must render: {contents:?}"
        );
        assert!(
            !contents
                .iter()
                .any(|c| c.contains("did not receive a final assistant answer")),
            "lazy-bound continuation must NOT show the fallback card: {contents:?}"
        );
    }

