    /// `/goal stop` stages a user-owned terminal transition to `complete`
    /// through the same get-then-set dance as pause/resume, and works from
    /// `blocked` (the #1693 circuit-breaker state).
    #[test]
    fn goal_stop_stages_complete_transition_from_blocked() {
        let mut store = protocol_store_with_autonomy();
        let session_id = SessionKey("local:test".into());
        store.state.set_session_goal(
            &session_id,
            Some(octos_core::ui_protocol::UiGoalRecord {
                profile_id: Some("coding".into()),
                goal_id: "goal_01".into(),
                objective: "stuck work".into(),
                status: "blocked".into(),
                token_budget: 1000,
                tokens_used: 10,
                time_used_seconds: 5,
                created_at_ms: 1,
                updated_at_ms: 2,
            }),
            Some("backend".into()),
        );
        store.state.composer = "/goal stop".into();
        match store.compose_command().expect("dispatch") {
            AppUiCommand::GetSessionGoal(params) => {
                assert_eq!(params.session_id, session_id);
            }
            other => panic!("expected GetSessionGoal, got {other:?}"),
        }
        let pending = store
            .state
            .pending_goal_transition
            .as_ref()
            .expect("stop stages a transition");
        assert_eq!(pending.status, "complete");
        assert_eq!(pending.action, crate::model::SessionGoalSetAction::Stop);

        // The refreshed goal (still blocked) must yield the follow-up set
        // with status=complete and the SERVER objective.
        let command = store.consume_pending_goal_transition(
            &session_id,
            Some(&octos_core::ui_protocol::UiGoalRecord {
                profile_id: Some("coding".into()),
                goal_id: "goal_01".into(),
                objective: "server truth".into(),
                status: "blocked".into(),
                token_budget: 1000,
                tokens_used: 10,
                time_used_seconds: 5,
                created_at_ms: 1,
                updated_at_ms: 3,
            }),
        );
        match command.expect("set dispatched") {
            AppUiCommand::SetSessionGoal(params) => {
                assert_eq!(params.status.as_deref(), Some("complete"));
                assert_eq!(params.objective, "server truth");
                assert_eq!(params.action, crate::model::SessionGoalSetAction::Stop);
            }
            other => panic!("expected SetSessionGoal, got {other:?}"),
        }
    }

    /// Resuming a goal that is still over budget re-activates it server-side
    /// but the scheduler will never fire — the status line must say how to
    /// actually un-freeze it (raise the budget), not read as a silent no-op.
    #[test]
    fn goal_resume_over_budget_hints_budget_raise() {
        let mut store = protocol_store_with_autonomy();
        let session_id = SessionKey("local:test".into());
        let over_budget = octos_core::ui_protocol::UiGoalRecord {
            profile_id: Some("coding".into()),
            goal_id: "goal_01".into(),
            objective: "big refactor".into(),
            status: "budget_limited".into(),
            token_budget: 1000,
            tokens_used: 1200,
            time_used_seconds: 60,
            created_at_ms: 1,
            updated_at_ms: 2,
        };
        store.state.set_session_goal(
            &session_id,
            Some(over_budget.clone()),
            Some("backend".into()),
        );
        store.state.composer = "/goal resume".into();
        let _ = store.compose_command().expect("stages the transition");
        let command = store.consume_pending_goal_transition(&session_id, Some(&over_budget));
        assert!(command.is_some(), "resume still dispatches the set");
        assert!(
            store.state.status.contains("--budget"),
            "over-budget resume must hint the budget raise: {}",
            store.state.status
        );
    }

    /// Every goal STATUS TRANSITION surfaces a status-line toast (#329) —
    /// the chip repaints silently, so a frozen/blocked goal used to go
    /// unnoticed. Same-status updates keep the generic message.
    #[test]
    fn goal_status_transitions_toast_distinctly() {
        use octos_core::ui_protocol::{SessionGoalUpdatedEvent, UiGoalRecord};
        let mut store = protocol_store_with_autonomy();
        let session_id = SessionKey("local:test".into());
        let goal = |status: &str| UiGoalRecord {
            profile_id: Some("coding".into()),
            goal_id: "goal_01".into(),
            objective: "long task".into(),
            status: status.into(),
            token_budget: 1000,
            tokens_used: 100,
            time_used_seconds: 10,
            created_at_ms: 1,
            updated_at_ms: 2,
        };
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionGoalUpdated(
            SessionGoalUpdatedEvent {
                session_id: session_id.clone(),
                profile_id: Some("coding".into()),
                goal: goal("active"),
                transition_actor: "user".into(),
            },
        )));
        // active -> blocked: distinct toast with the recovery hint.
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionGoalUpdated(
            SessionGoalUpdatedEvent {
                session_id: session_id.clone(),
                profile_id: Some("coding".into()),
                goal: goal("blocked"),
                transition_actor: "backend".into(),
            },
        )));
        assert!(
            store.state.status.contains("/goal resume"),
            "blocked toast must carry the recovery hint: {}",
            store.state.status
        );
        // blocked -> blocked (same status): generic update message.
        store.apply_event(AppUiEvent::Protocol(UiNotification::SessionGoalUpdated(
            SessionGoalUpdatedEvent {
                session_id: session_id.clone(),
                profile_id: Some("coding".into()),
                goal: goal("blocked"),
                transition_actor: "backend".into(),
            },
        )));
        assert!(
            store.state.status.starts_with("Goal updated:"),
            "same-status update keeps the generic message: {}",
            store.state.status
        );
    }

    #[test]
    fn goal_pause_carries_server_objective_not_stale_cache() {
        // Audit follow-up: when the cached mirror has drifted (local
        // says "X", server says "Y"), the pause/resume transition must
        // forward server truth — not the stale cache — to the backend.
        // Otherwise the set call would silently overwrite the server's
        // current objective with the TUI's outdated copy.
        use crate::client_event::{AutonomyClientEvent, AutonomyResult, ClientEvent};
        let mut store = protocol_store_with_autonomy();
        let session_id = SessionKey("local:test".into());

        // Cache holds the stale "X".
        let stale_goal = octos_core::ui_protocol::UiGoalRecord {
            profile_id: Some("coding".into()),
            goal_id: "goal_01".into(),
            objective: "X (stale cache)".into(),
            status: "active".into(),
            token_budget: 1000,
            tokens_used: 0,
            time_used_seconds: 0,
            created_at_ms: 1,
            updated_at_ms: 2,
        };
        store
            .state
            .set_session_goal(&session_id, Some(stale_goal), Some("user".into()));

        // User issues /goal pause — dispatch returns `session/goal/get`
        // (not `session/goal/set`), and stages the transition.
        store.state.composer = "/goal pause".into();
        match store.compose_command().expect("dispatch") {
            AppUiCommand::GetSessionGoal(_) => {}
            other => panic!("pause should refresh first, got {other:?}"),
        }

        // Server responds with the FRESH objective "Y" (the cache has
        // drifted — what the server actually has on file).
        let fresh_goal = octos_core::ui_protocol::UiGoalRecord {
            profile_id: Some("coding".into()),
            goal_id: "goal_01".into(),
            objective: "Y (server truth)".into(),
            status: "active".into(),
            token_budget: 1000,
            tokens_used: 0,
            time_used_seconds: 0,
            created_at_ms: 1,
            updated_at_ms: 7,
        };
        let follow_up = store
            .apply_client_event(ClientEvent::Autonomy(AutonomyClientEvent {
                result: AutonomyResult::GoalGet(crate::model::SessionGoalGetResult {
                    session_id: session_id.clone(),
                    profile_id: Some("coding".into()),
                    goal: Some(fresh_goal),
                }),
            }))
            .expect("goal_get response triggers the staged transition");

        // The follow-up must be `session/goal/set` carrying SERVER's
        // "Y", NOT the cached "X".
        match follow_up {
            AppUiCommand::SetSessionGoal(params) => {
                assert_eq!(
                    params.objective, "Y (server truth)",
                    "pause must forward refreshed server objective, not stale cache"
                );
                assert_eq!(params.status.as_deref(), Some("paused"));
                assert_eq!(params.action, crate::model::SessionGoalSetAction::Pause);
            }
            other => panic!("expected SetSessionGoal follow-up, got {other:?}"),
        }
        // Pending transition is consumed.
        assert!(store.state.pending_goal_transition.is_none());
    }

    #[test]
    fn goal_pause_aborts_when_refresh_returns_complete_status() {
        // If the server reports the goal is now `complete` between
        // dispatch and refresh, the staged pause must abort — the TUI
        // never reactivates a model-completed goal.
        use crate::client_event::{AutonomyClientEvent, AutonomyResult, ClientEvent};
        let mut store = protocol_store_with_autonomy();
        let session_id = SessionKey("local:test".into());

        store.state.set_session_goal(
            &session_id,
            Some(octos_core::ui_protocol::UiGoalRecord {
                profile_id: Some("coding".into()),
                goal_id: "g".into(),
                objective: "ongoing".into(),
                status: "active".into(),
                token_budget: 1000,
                tokens_used: 0,
                time_used_seconds: 0,
                created_at_ms: 1,
                updated_at_ms: 2,
            }),
            Some("user".into()),
        );
        store.state.composer = "/goal pause".into();
        let _ = store.compose_command().expect("dispatch get");

        // Server's refresh shows the model marked the goal complete
        // while the user was typing.
        let follow_up = store.apply_client_event(ClientEvent::Autonomy(AutonomyClientEvent {
            result: AutonomyResult::GoalGet(crate::model::SessionGoalGetResult {
                session_id: session_id.clone(),
                profile_id: Some("coding".into()),
                goal: Some(octos_core::ui_protocol::UiGoalRecord {
                    profile_id: Some("coding".into()),
                    goal_id: "g".into(),
                    objective: "ongoing".into(),
                    status: "complete".into(),
                    token_budget: 1000,
                    tokens_used: 1000,
                    time_used_seconds: 1,
                    created_at_ms: 1,
                    updated_at_ms: 9,
                }),
            }),
        }));
        assert!(
            follow_up.is_none(),
            "must not fire pause against a complete goal"
        );
        assert!(store.state.pending_goal_transition.is_none());
        assert!(
            store.state.status.to_lowercase().contains("complete"),
            "expected complete-state diagnostic, got: {}",
            store.state.status
        );
    }

